import{_ as u,W as s,X as l,Y as e,Z as t,$ as a,a1 as n,a0 as i,D as d}from"./framework-9199a8c2.js";const C={},p={href:"https://doi.org/10.1109/ICCV.2017.74",target:"_blank",rel:"noopener noreferrer"},c={class:"table-of-contents"},h=e("p",null,"基于梯度定位的深度网络视觉解释",-1),N=e("h2",{id:"_0-摘要",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_0-摘要","aria-hidden":"true"},"#"),t(" 0. 摘要")],-1),_={href:"https://github.com/ramprs/grad-cam/",target:"_blank",rel:"noopener noreferrer"},A={href:"https://youtu.be/COjUB9Izk6E",target:"_blank",rel:"noopener noreferrer"},G=i('<h2 id="_1-引言" tabindex="-1"><a class="header-anchor" href="#_1-引言" aria-hidden="true">#</a> 1. 引言</h2><p>卷积神经网络( Convolutional Neural Networks，CNNs )等深度网络在各种计算机视觉任务中取得了前所未有的突破，从图像分类[ 24、16]到目标检测[ 15 ]、语义分割[ 27 ]、图像描述[ 43、6、12、21]，以及最近的视觉问答[ 3、14、32、36]。虽然这些深度神经网络具有优越的性能，但它们缺乏可分解为直观和可理解的组件，使它们难以解释[ 26 ]。因此，当今天的智能系统出现故障时，他们在没有警告或解释的情况下，令人惊讶地失败了，让用户盯着一个不连贯的输出，想知道为什么。</p><p><strong>可解释性很重要</strong>。为了在智能系统中建立信任，并朝着他们有意义地融入我们的日常生活迈进，显然我们必须构建&quot;透明&quot;的模型来解释他们为什么预测他们所预测的。从广义上讲，这种透明度在人工智能( AI )进化的三个不同阶段都是有用的。首先，当人工智能明显弱于人类且尚未可靠&quot;可部署&quot;的(例如,视觉问答)时，透明和解释的目标是识别失效模式[ 1、17]，从而帮助研究人员将精力集中在最富有成果的研究方向上。其次，当人工智能与人类平起平坐、可靠&quot;可部署&quot;的(例如,在足够多的数据上训练的一组类别上进行图像分类)时，其目标是建立对用户适当的信任和信心。第三，当AI显著强于人类(例如象棋或围棋)时，解释的目标是在机器教学中[ 20 ] - -即机器教人类如何做出更好的决策。</p><p>通常存在准确性与简洁性或可解释性之间的权衡。经典的基于规则或专家系统[ 18 ]具有很强的可解释性，但并不十分精确(或健壮)。每个阶段都是手工设计的可分解管道被认为更具有可解释性，因为每个单独的组件都假设一个自然的直观解释。通过使用深度模型，我们将可解释模块牺牲为不可解释模块，通过更大的抽象(更多的层)和更紧密的集成(端到端训练)来获得更大的性能。最近引入的深度残差网络(深度残差网络) [ 16 ]深度超过200层，在一些具有挑战性的任务中表现出了最先进的性能。这种复杂性使得这些模型难以解释。因此，深度模型开始探索可解释性和准确性之间的边界线。</p><p>Zhou等[ 47 ]最近提出了一种名为类激活映射( CAM )的技术，用于识别不包含任何全连接层的受限类图像分类CNN所使用的判别区域。从本质上讲，这项工作权衡了模型的复杂性和性能，使模型的工作更加透明。相比之下，我们在不改变现有深度模型架构的情况下，使其具有可解释性，从而避免了可解释性与准确性之间的权衡。我们的方法是CAM的一个推广[ 47 ]，并且适用于更广泛的CNN模型家族：( 1 )具有全连接层的CNNs (例如. VGG )，( 2 )用于结构化输出(例如字幕)的CNNs，( 3 )用于具有多模态输入的任务的CNNs (例如. VQA )或强化学习，不需要改变结构或重新训练或任何次级学习组件。</p><p>是什么做出了很好的视觉解释?考虑图像分类[ 9 ] - -从模型中&quot;好&quot;的视觉解释来证明任何目标类别应该是( a )类判别(即对图像中的类别进行定位)和( b )高分辨率(即捕获细粒度细节)。</p><p>图1显示了&quot;老虎猫&quot;类(顶部)和&quot;拳击手&quot; (狗)类(底部)的可视化输出。像元间隔梯度可视化如向导反向传播[ 42 ]、反卷积[ 45 ]等是高分辨率的，突出图像中的细粒度细节，但不是类判别的(图1b和图1h非常相似)。</p><p>相比之下，像CAM或我们提出的梯度加权类激活映射( Gradient-weighted Class Activation Mapping，Grad-CAM )这样的定位方法是高度类判别的( &quot;猫&quot;的解释只突出图1c中的&quot;猫&quot;区域而不突出&quot;狗&quot;区域,反之亦然)。</p><p>为了结合两者的优点，我们表明可以将现有的像元间隔梯度可视化与Grad - CAM融合，以创建兼具高分辨率和类别区分性的Guided Grad - CAM可视化。因此，即使图像包含多个可能概念的证据，图像中与任何感兴趣决策相对应的重要区域也会被高分辨率的细节可视化，如图1d和1j所示。当对&quot;虎猫&quot;进行可视化时，Guided Grad - CAM不仅突出了猫的区域，还突出了猫身上的条纹，这对于预测特定品种的猫具有重要意义。综上所述，我们的贡献如下：( 1 )我们提出了Grad - CAM，一种基于类别判别的定位技术，可以从任何基于CNN的网络中生成视觉解释，而不需要进行架构更改或重新训练。我们评估了Grad - CAM的定位能力( 4.1节)和模型忠实性( 5.3节)，其优于基线。( 2 )将Grad - CAM应用于现有的表现最好的分类、描述( 7.1节)和VQA ( 7.2节)模型。对于图像分类，我们的可视化有助于识别数据集偏差( 6.2节)，并深入了解当前CNN的失败( 6.1节)，表明看似不合理的预测有合理的解释。对于标题和VQA，我们的可视化展示了一个令人惊讶的发现，普通的CNN + LSTM模型往往擅长定位具有判别性的图像区域，尽管没有在接地的图像-文本对上进行训练。( 3 )将深度残差网络[ 16 ]应用于图像分类和VQA ( 7.2节)。从深层到浅层，当遇到不同输出维度的层时，Grad - CAM的判别能力显著降低。( 4 )我们进行了人类研究(第5节)，表明Guided Grad - CAM的解释是类区分的，不仅帮助人类建立信任，而且还帮助未经训练的用户成功地从&quot;弱&quot;网络中识别出一个&quot;强&quot;网络，即使两者都做出了相同的预测。</p><h2 id="_2-相关工作" tabindex="-1"><a class="header-anchor" href="#_2-相关工作" aria-hidden="true">#</a> 2. 相关工作</h2><p>我们的工作借鉴了最近在CNN可视化、模型信任评估和弱监督定位方面的工作。可视化CNNs。以前的一些工作[ 40、42、45、13]通过突出&quot;重要&quot;像素(即这些像素的强度变化对预测评分的影响最大)来可视化CNN预测。具体来说，西蒙尼扬等人[ 40 ]通过像素强度对预测类别分数的偏导数进行可视化，而Guided反向误差传播网络(B—P) [ 42 ]和Deconvolution [ 45 ]对&quot;原始&quot;梯度进行修改，从而得到定性的改进。这些方法在文献[ 30 ]中进行了比较。尽管这些方法产生了细粒度的可视化，但它们并不具有类区分性。关于不同类的可视化几乎完全相同(见图1b和1h)。</p><p>其他可视化方法通过合成图像来最大限度地激活一个网络单元[ 40、11]或反转一个潜在的表示[ 31、10]。虽然这些可以是高分辨率和类别区分性的，但它们可视化的是一个模型，而不是针对特定输入图像的预测。</p><p><strong>评估模型信任</strong>。受可解释性[ 26 ]和评估模型中的信任[ 37 ]等概念的启发，我们通过人类研究以类似[ 37 ]的方式评估Grad - CAM可视化，以表明它们可以成为用户评估和放置自动化系统中信任的重要工具。</p><p><strong>弱监督定位</strong>。另一个相关的工作是CNNs背景下的弱监督定位，其任务是仅使用整个图像类标签[ 7、33、34、47]来定位图像中的物体。</p><p>与我们的方法最相关的是类激活映射( CAM )定位方法[ 47 ]。该方法修改了图像分类CNN架构，将全连接层替换为卷积层和全局平均池化[ 25 ]，从而获得特定类别的特征图。其他人研究了使用全局最大池化[ 34 ]和log - sum - exp池化[ 35 ]的类似方法。</p><p>CAM的一个缺点是它要求特征图直接在softmax层之前，因此它只适用于在预测(即conv特征图→全局平均池化→softmax层)之前对卷积图进行全局平均池化的特定CNN架构。这种结构在某些任务(例如图像分类)上可能比一般的网络获得更低的精度，或者根本不适用于任何其他任务(例如图像描述或VQA)。我们介绍了一种新的使用梯度信号来组合特征图的方式，这种方式在网络架构中不需要任何修改。这使得我们的方法可以应用于任何基于CNN的架构，包括图像描述和视觉问答。对于全卷积架构，Grad - CAM退化为CAM。因此，Grad - CAM是对CAM的推广。</p><p>其他方法通过对输入图像的扰动进行分类来实现定位。Zeiler和Fergus [ 45 ]通过遮挡块扰动输入并对被遮挡的图像进行分类，通常会导致当相关对象被遮挡时，相关对象的分类得分较低。这一原理在文献[ 4 ]中被应用于定位。Oquab等[ 33 ]对包含一个像素的多个图斑进行分类，然后将这些图斑的类得分进行平均，以提供该像素的类得分。与这些不同的是，我们的方法在一次拍摄中实现了定位；它只需要每幅图像的一次前向和部分后向传递，因此通常效率要高一个数量级。在最近的工作中，Zhang等[ 46 ]引入了对比边际获胜概率( c-MWP )，这是一种概率性的Winner - Take - All公式，用于对神经分类模型的自上而下注意力进行建模，可以突出具有判别性的区域。这比Grad - CAM慢，与CAM一样，只适用于图像分类CNN。此外，定量和定性结果均不如Grad - CAM (见Sec . 4.1和[38])。</p><h2 id="_3-方法" tabindex="-1"><a class="header-anchor" href="#_3-方法" aria-hidden="true">#</a> 3. 方法</h2><p>先前的一些工作已经断言，CNN中更深层次的表示捕获了更高层次的视觉结构[ 5、31]。此外，卷积特征天然地保留了全连接层丢失的空间信息，因此我们可以期待最后一个卷积层在高层语义和细节空间信息之间有最好的折中。这些层中的神经元在图像(说对象部分)中寻找语义类别特定的信息。Grad - CAM利用流入CNN最后一个卷积层的梯度信息来理解每个神经元对于感兴趣决策的重要性。<em>虽然我们的技术非常通用，可以用来可视化深度网络中的任何激活，但在这项工作中，我们专注于解释网络可能做出的决策。</em></p><hr><p>个人理解:</p><p>Grad-cam本质就是链式求导获得梯度，但在求导的过程中引入了Relu函数来保证只获取对结果起积极作用的部分。</p>',22),M={href:"https://github.com/jacobgil/pytorch-grad-cam",target:"_blank",rel:"noopener noreferrer"};function q(f,g){const o=d("ExternalLinkIcon"),r=d("router-link");return s(),l("div",null,[e("p",null,[e("a",p,[t("文章链接"),a(o)])]),e("nav",c,[e("ul",null,[e("li",null,[a(r,{to:"#_0-摘要"},{default:n(()=>[t("0. 摘要")]),_:1})]),e("li",null,[a(r,{to:"#_1-引言"},{default:n(()=>[t("1. 引言")]),_:1})]),e("li",null,[a(r,{to:"#_2-相关工作"},{default:n(()=>[t("2. 相关工作")]),_:1})]),e("li",null,[a(r,{to:"#_3-方法"},{default:n(()=>[t("3. 方法")]),_:1})])])]),h,N,e("p",null,[t(`我们提出了一种从基于卷积神经网络( Convolutional Neural Network，CNN )的大型模型中为决策产生"视觉解释"的技术，使其更加透明。我们的方法- -梯度加权类激活映射( Gradient-weighted Class Activation Mapping，Grad-CAM )，使用任何目标概念(说logits是'狗' ,甚至是字幕)的梯度，流入最后的卷积层，产生一个突出图像中重要区域的粗定位图，用于预测概念。与以前的方法不同，Grad CAM适用于各种各样的CNN模型家族：( 1 )具有全连接层的CNN (例如：VGG )，( 2 )用于结构化输出(如字幕)的CNNs，( 3 )用于具有多模态输入(例如,视觉问答)或强化学习的任务，而不需要结构变化或重新训练。我们将Grad - CAM与现有的细粒度可视化相结合，创建了一种高分辨率的类别判别可视化Guided Grad-CAM，并将其应用于图像分类、图像描述和视觉问答( VQA )模型，包括基于ResNet的架构。在图像分类模型方面，我们的可视化( a )有助于深入了解这些模型的失败模式(表明看似不合理的预测有合理的解释)，( b )在ILSVRC - 15弱监督定位任务上优于以前的方法，( c )更忠实于底层模型，( d )通过识别数据集偏差帮助实现模型泛化。对于图像描述和VQA，我们的可视化显示即使非注意力模型也能定位输入。最后，我们设计并进行了人类研究，以衡量Grad - CAM解释是否有助于用户在深度网络的预测中建立适当的信任，并表明Grad - CAM帮助未经训练的用户成功地从一个"弱"的网络中识别出一个"强"的网络，即使两者都做出了相同的预测。我们的代码可在`),e("a",_,[t("Github"),a(o)]),t("以及CloudCV上的演示[ 2 ] 1和"),e("a",A,[t("Youtube网站"),a(o)]),t("上的视频获得。")]),G,e("p",null,[t("文章后面大多是实验，感兴趣的可以照着原文实验效果。附一个"),e("a",M,[t("Pytorch-Grad-CAM工具"),a(o)])])])}const b=u(C,[["render",q],["__file","selvaraju2017gradcam.html.vue"]]);export{b as default};
